func (i *Instance) collectResourceUsage() (float64, float64, bool) {
	if !i.started || i.tmuxSession == nil {
		return 0, 0, false
	}

	pid, err := i.tmuxSession.GetPanePID()
	if err != nil {
		return 0, 0, false
