package session

import (
	"os/exec"
	"runtime"
	"strings"
)

// NotificationsEnabled controls whether desktop notifications are sent.
// Set from config at startup.
var NotificationsEnabled = true

// SendNotification fires a desktop notification. The underlying command is
// started but not awaited — callers do not block on OS notification delivery.
func SendNotification(title, body string) {
	if !NotificationsEnabled {
		return
	}
	switch runtime.GOOS {
	case "darwin":
		sendDarwin(title, body)
	case "linux":
		sendLinux(title, body)
	}
}

// sendDarwin delivers a notification via osascript on macOS.
func sendDarwin(title, body string) {
	script := `display notification "` + escapeAppleScript(body) +
		`" with title "` + escapeAppleScript(title) + `"`
	_ = exec.Command("osascript", "-e", script).Start()
}

// sendLinux delivers a notification via notify-send on Linux.
// The call is a no-op when notify-send is not installed.
func sendLinux(title, body string) {
	path, err := exec.LookPath("notify-send")
	if err != nil {
		return
	}
	_ = exec.Command(path, title, body).Start()
}

// escapeAppleScript escapes backslashes and double-quotes for use inside
// an AppleScript string literal.
func escapeAppleScript(s string) string {
	s = strings.ReplaceAll(s, `\`, `\\`)
	s = strings.ReplaceAll(s, `"`, `\"`)
	return s
}

package session

import (
	"testing"

	"github.com/stretchr/testify/assert"
)

func TestEscapeAppleScript(t *testing.T) {
	tests := []struct {
		name  string
		input string
		want  string
	}{
		{
			name:  "no special chars",
			input: "hello world",
			want:  "hello world",
		},
		{
			name:  "double quote",
			input: `say "hello"`,
			want:  `say \"hello\"`,
		},
		{
			name:  "backslash",
			input: `path\to\file`,
			want:  `path\\to\\file`,
		},
		{
			name:  "backslash before quote",
			input: `\"`,
			want:  `\\\"`,
		},
		{
			name:  "empty string",
			input: "",
			want:  "",
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			got := escapeAppleScript(tt.input)
			assert.Equal(t, tt.want, got)
		})
	}
}

func TestSendNotificationDisabled(t *testing.T) {
	// When notifications are disabled, SendNotification must be a no-op.
	// We verify by temporarily disabling and ensuring it doesn't panic or exec.
	orig := NotificationsEnabled
	NotificationsEnabled = false
	defer func() { NotificationsEnabled = orig }()

	// Should return without error and without launching any process.
	assert.NotPanics(t, func() {
		SendNotification("test title", "test body")
	})
